#!/usr/bin/env perl
use strict;
use warnings FATAL => 'all';  # Enable all warning messages, not just deprecated ones (FATAL is the default)
require CGI qw(:standard);   # Include standard Perl modules for handling GET and POST parameters.

my $redirect_url = $ENV{'HTTP_REFERER'} // 'http://default-website/';  # Default redirect URL if no referrer provided by client (e.g., via browser history).
print "Content-type: text/plain\n\n";   # Set the content type to plaintext for simplicity and compatibility with CGI scripts, not necessary in this case but included here just as a reminder of what we're doing! 
my $next = param('next');    # Get 'next', which is expected from POST data. If no such parameter exists (i.e., the user has navigated away), default to our homepage ('http://default-website/').  
if($next){                    # Check if a redirect URL was provided in $_POST, and use it as fallback otherwise – this is how we handle POST data with CGI. If no such parameter exists (i.e., the user has navigated away), default to our homepage ('http://default-website/').
    $redirect_url = $next;     # Use '$next' as redirect URL if it was provided in $POST, otherwise use a fallback value of http://default-site/.  This is how we handle POST data with CGI. If no such parameter exists (i.e., the user has navigated away), default to our homepage ('http://default-website/').
}    # End if block for checking $next existence and setting redirect URL accordingly!  
print "Location: $redirect_url\n";  # Print a Location header with '$redirect_URL' as the value, which will cause browser to navigate there. This is how we handle redirection in CGI scripts using Perl (and not via HTML).